from typing import List

class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        root_x = self.find(x)
        root_y = self.find(y)
        if root_x != root_y:
            if self.rank[root_x] > self.rank[root_y]:
                self.parent[root_y] = root_x
            elif self.rank[root_x] < self.rank[root_y]:
                self.parent[root_x] = root_y
            else:
                self.parent[root_y] = root_x
                self.rank[root_x] += 1
            return True
        return False

class Solution:
    def maxStability(self, n: int, edges: List[List[int]], k: int) -> int:
        must_edges = []
        optional_edges = []
        for u, v, s, must in edges:
            if must:
                must_edges.append((u, v, s))
            else:
                optional_edges.append((u, v, s))

        uf = UnionFind(n)
        for u, v, s in must_edges:
            if not uf.union(u, v):
                return -1

        if uf.find(0) != uf.find(n - 1):
            return -1

        optional_edges.sort(key=lambda x: x[2], reverse=True)
        upgrades = k
        res = float('inf')
        for u, v, s in optional_edges:
            if uf.union(u, v):
                res = min(res, s * (1 << min(upgrades, 1)))
                upgrades -= 1
                if upgrades < 0:
                    break

        count = n - 1 - len(must_edges)
        if count > k:
            return -1

        return res if res != float('inf') else -1
